package io.spdigital.ubm.admin.controller;

import static io.spdigital.ubm.common.Constants.DEFAULT_PAGE_NUMBER;
import static io.spdigital.ubm.common.Constants.DEFAULT_PAGE_SIZE;
import static io.spdigital.ubm.common.Constants.DEFAULT_SORT_DIRECTION;

import io.spdigital.ubm.admin.dto.GetCustomerResponse;
import io.spdigital.ubm.admin.dto.Subscription;
import io.spdigital.ubm.admin.dto.UpdateBpNo;
import io.spdigital.ubm.admin.service.AdminService;
import io.spdigital.ubm.admin.service.UserService;
import io.spdigital.ubm.common.SecurityContextHeader;
import io.spdigital.ubm.common.UserUtil;
import io.spdigital.ubm.logging.Loggable;
import io.spdigital.ubm.model.dto.BaseResponse;
import io.spdigital.ubm.model.dto.Yggdrasil;
import io.spdigital.ubm.model.dto.Yggdrasil.SearchCustomers;
import java.util.List;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.servlet.function.ServerResponse;
import reactor.core.publisher.Mono;

@Slf4j
@RestController
@RequestMapping("/admin")
@RequiredArgsConstructor
public class AdminController {

	private final AdminService adminService;

	private final UserService userService;

	@Loggable
	@GetMapping(value = "/customers")
	public Mono<SearchCustomers.Response> getCustomers(@RequestParam String type, @RequestParam String searchString,
			@RequestParam(defaultValue = DEFAULT_PAGE_NUMBER) Integer pageNumber,
			@RequestParam(defaultValue = DEFAULT_PAGE_SIZE) Integer pageSize,
			@RequestParam(defaultValue = DEFAULT_SORT_DIRECTION) String direction) {
		log.info("AdminController :: searchCustomers :: Start");
		return adminService.getCustomers(type, searchString, pageNumber, pageSize, direction);
	}

	@Loggable
	@GetMapping(value = "/customer")
	public Mono<GetCustomerResponse> getCustomer(@RequestParam String bpNo, @RequestParam String userId) {
		log.info("AdminController :: getCustomerDetails :: Start");
		return adminService.getCustomer(bpNo, userId);
	}

	@Loggable
	@PostMapping("/bpNos")
	public Mono<UpdateBpNo.Response> bpNos(@RequestBody UpdateBpNo.Request request) {
		return adminService.updateBpNos(request);
	}

	@Loggable
	@GetMapping("/bpNos/accountNo/{accountNo}")
	public Mono<ResponseEntity<String>> getBpNoByAccountNo(@PathVariable String accountNo) {
		log.info("Retrieving bpNo by AccountNo information...");
		return adminService.getBpNoByAccountNo(accountNo)
			.flatMap(res -> Mono.just(ResponseEntity.ok().body(res)))
			.onErrorResume(e -> Mono.just(ResponseEntity.noContent().build()));
	}

	@Loggable
	@GetMapping("/bpNos/userId/{userId}")
	public Mono<List<String>> getBpNosByUserId(@PathVariable String userId) {
		log.info("Retrieving bpNos by UserId information...");
		return adminService.getBpNosByUserId(userId);
	}

	@Loggable
	@PostMapping("/subscription")
	public Mono<BaseResponse> updateSubscription(@RequestBody Subscription.Update.Request request) {
		log.info("Updating subscription information...");
		return adminService.updateSubscription(request);
	}

	@Loggable
	@PostMapping("/retrieve/subscription")
	public Mono<Subscription.Retrieve.Response> getSubscription(@RequestBody Subscription.Retrieve.Request request) {
		log.info("Retrieving subscription information...");
		return adminService.getSubscription(request);
	}

	@Loggable
	@DeleteMapping("/users/delink")
	public Mono<BaseResponse> delink(@RequestBody Yggdrasil.User.Request request) {
		return adminService.delink(request);
	}

	@Loggable
	@GetMapping("/users/forgot-password")
	public Mono<BaseResponse> forgotPassword(@RequestParam("email") String email) {
		return userService.forgotPassword(email);
	}

}

